// Helpers
const Badge=({s})=>{const l=s?.toLowerCase()||"";let c;if(l.includes("complete")||l==="approved")c={bg:B.okBg,fg:B.green};else if(l.includes("progress"))c={bg:B.infoBg,fg:B.info};else if(l.includes("pending")||l.includes("review"))c={bg:B.warnBg,fg:B.warn};else if(l.includes("hold"))c={bg:"#f5f5f5",fg:"#888"};else if(l==="rejected")c={bg:B.dangerBg,fg:B.danger};else c={bg:B.warnBg,fg:B.warn};return<span style={{background:c.bg,color:c.fg,border:`1px solid ${c.fg}30`,padding:"2px 8px",borderRadius:5,fontSize:10,fontWeight:600,whiteSpace:"nowrap"}}>{s}</span>};
const Prio=({p})=>{const c={Critical:B.danger,High:B.warn,Medium:B.info,Low:B.green}[p]||"#999";return<span style={{display:"inline-flex",alignItems:"center",gap:3,fontSize:10,fontWeight:600,color:c}}><span style={{width:6,height:6,borderRadius:"50%",background:c}}/>{p}</span>};
const PB=({v,h=5})=><div style={{width:"100%",background:"#e8eaf0",borderRadius:h,height:h,overflow:"hidden"}}><div style={{width:`${v}%`,height:"100%",borderRadius:h,background:v===100?B.green:v>60?B.purple:v>30?B.warn:B.danger,transition:"width 0.4s"}}/></div>;
const Av=({n,sz=32,lv})=>{const cs=["#0F0F83","#4C4CCC","#1FB15A","#e53e3e","#ed8936","#3182ce","#805AD5"];return<div style={{position:"relative",width:sz,height:sz,borderRadius:"50%",background:cs[n.charCodeAt(0)%cs.length],display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontWeight:600,fontSize:sz*.4,flexShrink:0}}>{n[0]}{lv&&<div style={{position:"absolute",bottom:-1,right:-1,width:11,height:11,borderRadius:"50%",background:B.warn,border:"2px solid #fff"}}/>}</div>};
const Pills=({p})=>!p?.length?null:<div style={{display:"flex",flexWrap:"wrap",gap:3}}>{p.map((x,i)=><span key={i} style={{display:"inline-flex",alignItems:"center",gap:2,padding:"1px 6px",borderRadius:8,background:`${B.navy}08`,border:`1px solid ${B.navy}10`,fontSize:9,fontWeight:500,color:B.navy}}><User size={8}/>{x}</span>)}</div>;
const Mc=({icon:I,label,value,sub,accent=B.navy,trend})=><div style={{background:B.card,borderRadius:12,padding:"14px 16px",border:`1px solid ${B.border}`,flex:1,minWidth:110}}><div style={{display:"flex",alignItems:"center",gap:6,marginBottom:6}}><div style={{width:28,height:28,borderRadius:8,background:`${accent}12`,display:"flex",alignItems:"center",justifyContent:"center"}}><I size={13} color={accent}/></div><span style={{fontSize:10,color:B.sub,fontWeight:500}}>{label}</span></div><div style={{display:"flex",alignItems:"baseline",gap:4}}><div style={{fontSize:22,fontWeight:700,color:B.text}}>{value}</div>{trend&&<span style={{fontSize:10,fontWeight:600,color:trend>0?B.green:B.danger,display:"flex",alignItems:"center",gap:1}}>{trend>0?<ArrowUp size={9}/>:<ArrowDown size={9}/>}{Math.abs(trend)}%</span>}</div>{sub&&<div style={{fontSize:9,color:B.muted,marginTop:1}}>{sub}</div>}</div>;

